namespace sv_06e8ceee075b4095a6f4225d91a29add.Client.Models;

public class Shipment
{
    public required string TrackingNumber { get; set; }
    public required string Status { get; set; }
    public required string Location { get; set; }
    public DateTimeOffset? EstimatedDelivery { get; set; }
    public List<StatusUpdate> StatusUpdates { get; set; } = [];
}

public class StatusUpdate
{
    public required string Description { get; set; }
    public required string Location { get; set; }
    public DateTimeOffset Timestamp { get; set; }
}

using sv_06e8ceee075b4095a6f4225d91a29add.Client.Models;

namespace sv_06e8ceee075b4095a6f4225d91a29add.Client.Services;

public interface IShipmentService
{
    Task<Shipment> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

using System.Net.Http.Json;
using sv_06e8ceee075b4095a6f4225d91a29add.Client.Models;

namespace sv_06e8ceee075b4095a6f4225d91a29add.Client.Services;

/// <summary>
/// HTTP-based implementation used when running on WebAssembly.
/// </summary>
public class ClientShipmentService(HttpClient httpClient) : IShipmentService
{
    public async Task<Shipment> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var shipment = await httpClient.GetFromJsonAsync<Shipment>(
            $"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);

        return shipment ?? throw new InvalidOperationException(
            $"Shipment '{trackingNumber}' not found.");
    }
}

using sv_06e8ceee075b4095a6f4225d91a29add.Client.Models;
using sv_06e8ceee075b4095a6f4225d91a29add.Client.Services;

namespace sv_06e8ceee075b4095a6f4225d91a29add.Services;

/// <summary>
/// Server-side implementation that simulates a slow backend with seeded data.
/// </summary>
public class ServerShipmentService : IShipmentService
{
    private static readonly Dictionary<string, Shipment> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["PKG-001"] = new Shipment
        {
            TrackingNumber = "PKG-001",
            Status = "In Transit",
            Location = "Chicago, IL",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 26, 17, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate
                {
                    Description = "Package picked up",
                    Location = "New York, NY",
                    Timestamp = new DateTimeOffset(2026, 5, 20, 9, 15, 0, TimeSpan.Zero)
                },
                new StatusUpdate
                {
                    Description = "Departed sorting facility",
                    Location = "Newark, NJ",
                    Timestamp = new DateTimeOffset(2026, 5, 20, 14, 30, 0, TimeSpan.Zero)
                },
                new StatusUpdate
                {
                    Description = "Arrived at regional hub",
                    Location = "Chicago, IL",
                    Timestamp = new DateTimeOffset(2026, 5, 21, 8, 45, 0, TimeSpan.Zero)
                }
            ]
        },
        ["PKG-002"] = new Shipment
        {
            TrackingNumber = "PKG-002",
            Status = "Delivered",
            Location = "San Francisco, CA",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 22, 12, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate
                {
                    Description = "Package picked up",
                    Location = "Los Angeles, CA",
                    Timestamp = new DateTimeOffset(2026, 5, 18, 10, 0, 0, TimeSpan.Zero)
                },
                new StatusUpdate
                {
                    Description = "In transit",
                    Location = "Bakersfield, CA",
                    Timestamp = new DateTimeOffset(2026, 5, 19, 6, 20, 0, TimeSpan.Zero)
                },
                new StatusUpdate
                {
                    Description = "Out for delivery",
                    Location = "San Francisco, CA",
                    Timestamp = new DateTimeOffset(2026, 5, 20, 7, 0, 0, TimeSpan.Zero)
                },
                new StatusUpdate
                {
                    Description = "Delivered — left at front door",
                    Location = "San Francisco, CA",
                    Timestamp = new DateTimeOffset(2026, 5, 20, 14, 35, 0, TimeSpan.Zero)
                }
            ]
        },
        ["PKG-003"] = new Shipment
        {
            TrackingNumber = "PKG-003",
            Status = "Label Created",
            Location = "Seattle, WA",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 28, 18, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate
                {
                    Description = "Shipping label created",
                    Location = "Seattle, WA",
                    Timestamp = new DateTimeOffset(2026, 5, 22, 16, 0, 0, TimeSpan.Zero)
                }
            ]
        }
    };

    public async Task<Shipment> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);

        if (!SeedData.TryGetValue(trackingNumber, out var shipment))
        {
            throw new KeyNotFoundException(
                $"No shipment found for tracking number '{trackingNumber}'.");
        }

        return shipment;
    }
}

@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_06e8ceee075b4095a6f4225d91a29add.Client.Models
@using sv_06e8ceee075b4095a6f4225d91a29add.Client.Services
@inject IShipmentService ShipmentService
@inject ILogger<TrackShipment> Logger
@implements IDisposable

<PageTitle>Track Shipment @TrackingNumber</PageTitle>

<h1>Shipment Tracking</h1>

@if (_loading)
{
    <div class="loading-placeholder">
        <p><em>Loading shipment details for @TrackingNumber…</em></p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_errorMessage</p>
        <button class="btn btn-outline-danger" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_shipment is not null)
{
    <div class="shipment-details">
        <h2>@_shipment.TrackingNumber</h2>
        <dl>
            <dt>Status</dt>
            <dd>@_shipment.Status</dd>
            <dt>Location</dt>
            <dd>@_shipment.Location</dd>
            @if (_shipment.EstimatedDelivery.HasValue)
            {
                <dt>Estimated Delivery</dt>
                <dd>@_shipment.EstimatedDelivery.Value.ToString("f")</dd>
            }
        </dl>

        @if (_shipment.StatusUpdates.Count > 0)
        {
            <h3>Tracking History</h3>
            <table class="table">
                <thead>
                    <tr>
                        <th>Date</th>
                        <th>Location</th>
                        <th>Description</th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var update in _shipment.StatusUpdates.OrderByDescending(u => u.Timestamp))
                    {
                        <tr>
                            <td>@update.Timestamp.ToString("g")</td>
                            <td>@update.Location</td>
                            <td>@update.Description</td>
                        </tr>
                    }
                </tbody>
            </table>
        }
    </div>
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = string.Empty;

    private Shipment? _shipment;
    private bool _loading;
    private string? _errorMessage;

    private CancellationTokenSource? _cts;

    protected override async Task OnParametersSetAsync()
    {
        // Cancel any in-flight request when the tracking number changes.
        CancelPending();

        _cts = new CancellationTokenSource();
        await LoadShipmentAsync(_cts.Token);
    }

    private async Task LoadShipmentAsync(CancellationToken ct)
    {
        _shipment = null;
        _errorMessage = null;
        _loading = true;

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, ct);
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // Navigation away or disposal — silently abandon.
            return;
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (TaskCanceledException ex) when (ex.InnerException is TimeoutException)
        {
            Logger.LogError(ex, "HTTP timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong while loading shipment details. Please try again.";
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task RetryAsync()
    {
        CancelPending();
        _cts = new CancellationTokenSource();
        await LoadShipmentAsync(_cts.Token);
    }

    private void CancelPending()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }

    public void Dispose()
    {
        CancelPending();
    }
}

